import React from 'react';

const AlertMessage = ({ type = 'info', message, onDismiss, showIcon = true }) => {
  // 根据类型确定样式
  const styles = {
    success: {
      bg: 'bg-green-50',
      text: 'text-green-800',
      iconColor: 'text-green-400',
      borderColor: 'border-green-400',
      detailsColor: 'text-green-700'
    },
    error: {
      bg: 'bg-red-50',
      text: 'text-red-800',
      iconColor: 'text-red-400',
      borderColor: 'border-red-400',
      detailsColor: 'text-red-700'
    },
    warning: {
      bg: 'bg-yellow-50',
      text: 'text-yellow-800',
      iconColor: 'text-yellow-400',
      borderColor: 'border-yellow-400',
      detailsColor: 'text-yellow-700'
    },
    info: {
      bg: 'bg-blue-50',
      text: 'text-blue-800',
      iconColor: 'text-blue-400',
      borderColor: 'border-blue-400',
      detailsColor: 'text-blue-700'
    }
  };

  const style = styles[type] || styles.info;

  // 根据类型选择图标
  const icons = {
    success: (
      <svg className={`h-5 w-5 ${style.iconColor}`} xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
        <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
      </svg>
    ),
    error: (
      <svg className={`h-5 w-5 ${style.iconColor}`} xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
        <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
      </svg>
    ),
    warning: (
      <svg className={`h-5 w-5 ${style.iconColor}`} xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
        <path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
      </svg>
    ),
    info: (
      <svg className={`h-5 w-5 ${style.iconColor}`} xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
        <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
      </svg>
    )
  };

  if (!message) return null;

  return (
    <div className={`mb-4 rounded-md ${style.bg} p-4`}>
      <div className="flex">
        {showIcon && (
          <div className="flex-shrink-0">
            {icons[type]}
          </div>
        )}
        <div className={`${showIcon ? 'ml-3' : ''} flex-grow`}>
          <div className={`text-sm font-medium ${style.text}`}>
            {typeof message === 'string' ? message : message.title}
          </div>
          {typeof message !== 'string' && message.details && (
            <div className={`mt-2 text-sm ${style.detailsColor}`}>
              <p>{message.details}</p>
            </div>
          )}
        </div>
        {onDismiss && (
          <div className="ml-auto pl-3">
            <div className="-mx-1.5 -my-1.5">
              <button
                type="button"
                onClick={onDismiss}
                className={`inline-flex rounded-md p-1.5 ${style.bg} ${style.text} hover:bg-gray-100 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-${style.borderColor} focus:ring-${style.borderColor}`}
              >
                <span className="sr-only">Dismiss</span>
                <svg className="h-5 w-5" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" aria-hidden="true">
                  <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                </svg>
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default AlertMessage;
